function confirmDelete(message='确定要删除吗？'){return confirm(message);}function showMessage(msg,type='success'){const colors={success:'#52c41a',error:'#ff4d4f',warning:'#fa8c16',info:'#1890ff'};const div=document.createElement('div');div.style.cssText=` position:fixed;top:20px;right:20px;padding:16px 24px;background:${colors[type]||colors.info};color:white;border-radius:8px;box-shadow:0 4px 16px rgba(0,0,0,0.15);z-index:9999;animation:slideIn 0.3s ease;`;div.textContent=msg;document.body.appendChild(div);setTimeout(()=>{div.style.animation='slideOut 0.3s ease';setTimeout(()=>div.remove(),300);},3000);}async function request(url,options={}){const defaultOptions={headers:{'Content-Type':'application/json',},};const response=await fetch(url,{...defaultOptions,...options});const data=await response.json();if(!data.success){throw new Error(data.message||'请求失败');}return data;}function formatDate(date,format='YYYY-MM-DD HH:mm:ss'){const d=new Date(date);const year=d.getFullYear();const month=String(d.getMonth()+1).padStart(2,'0');const day=String(d.getDate()).padStart(2,'0');const hours=String(d.getHours()).padStart(2,'0');const minutes=String(d.getMinutes()).padStart(2,'0');const seconds=String(d.getSeconds()).padStart(2,'0');return format .replace('YYYY',year).replace('MM',month).replace('DD',day).replace('HH',hours).replace('mm',minutes).replace('ss',seconds);}function formatMoney(amount,decimals=2){return '¥'+Number(amount).toFixed(decimals).replace(/\d(?=(\d{3})+\.)/g,'$&,');}function debounce(func,wait=300){let timeout;return function(...args){clearTimeout(timeout);timeout=setTimeout(()=>func.apply(this,args),wait);};}function logMenuClick(menuName){fetch('../api/log_operation.php',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({action:'点击菜单',detail:menuName,data:{menu:menuName}})}).catch(console.error);}const style=document.createElement('style');style.textContent=` @keyframes slideIn{from{transform:translateX(100%);opacity:0;}to{transform:translateX(0);opacity:1;}}@keyframes slideOut{from{transform:translateX(0);opacity:1;}to{transform:translateX(100%);opacity:0;}}`;document.head.appendChild(style);document.addEventListener('DOMContentLoaded',function(){document.querySelectorAll('.message').forEach(msg=>{setTimeout(()=>msg.remove(),5000);});});